195	func TestRouteStatus_RouteAttemptCooldownSurfaces(t *testing.T) {
196		svc := routeAttemptTestService(t, 30*time.Second)
197		recordedAt := time.Now().Add(-time.Second).UTC()
198		if err := svc.RecordRouteAttempt(context.Background(), RouteAttempt{
199			Harness:   "fiz",
200			Provider:  "bragi",
201			Model:     "qwen",
202			Status:    "failed",
203			Reason:    "rate_limit",
204			Error:     "429 too many requests",
205			Timestamp: recordedAt,
206		}); err != nil {
207			t.Fatalf("RecordRouteAttempt: %v", err)
208		}
209	
210		report, err := svc.RouteStatus(context.Background())
211		if err != nil {
212			t.Fatalf("RouteStatus: %v", err)
213		}
214		if len(report.Routes) != 1 {
215			t.Fatalf("Routes: got %d, want 1", len(report.Routes))
216		}
217		byProvider := make(map[string]RouteCandidateStatus)
218		for _, cand := range report.Routes[0].Candidates {
219			byProvider[cand.Provider] = cand
220		}
221		bragi := byProvider["bragi"]
222		if bragi.Healthy {
223			t.Fatal("bragi should be unhealthy while route-attempt cooldown is active")
224		}
225		if bragi.Cooldown == nil {
226			t.Fatal("bragi cooldown should be populated")
227		}
228		if bragi.Cooldown.Reason != "rate_limit" {
229			t.Fatalf("Cooldown.Reason: got %q, want rate_limit", bragi.Cooldown.Reason)
230		}
231		if bragi.Cooldown.LastError != "429 too many requests" {
232			t.Fatalf("Cooldown.LastError: got %q", bragi.Cooldown.LastError)
233		}
234		if !bragi.Cooldown.LastAttempt.Equal(recordedAt) {
235			t.Fatalf("Cooldown.LastAttempt: got %s, want %s", bragi.Cooldown.LastAttempt, recordedAt)
236		}
237		if !byProvider["openrouter"].Healthy {
238			t.Fatal("openrouter should remain healthy")
239		}
240	}
