242	func TestRouteAttempts_ProviderModelKeying(t *testing.T) {
243		svc := newTestService(t, ServiceOptions{})
244		ctx := context.Background()
245	
246		keyX := routing.ProviderModelKey("providerA", "", "modelX")
247		keyY := routing.ProviderModelKey("providerA", "", "modelY")
248	
249		for i := 0; i < 3; i++ {
250			if err := svc.RecordRouteAttempt(ctx, RouteAttempt{
251				Harness:  "fiz",
252				Provider: "providerA",
253				Model:    "modelX",
254				Status:   "failed",
255				Error:    "boom",
256				Duration: 100 * time.Millisecond,
257			}); err != nil {
258				t.Fatalf("RecordRouteAttempt failure %d on modelX: %v", i, err)
259			}
260		}
261	
262		successRate, latencyMS := svc.routeMetricSignals(time.Now(), 30*time.Second)
263		if got, want := successRate[keyX], 0.0; got != want {
264			t.Fatalf("after 3 failures on modelX: successRate[%s]=%v, want %v", keyX, got, want)
265		}
266		if _, ok := successRate[keyY]; ok {
267			t.Fatalf("modelY signal should be untouched by modelX failures, got successRate[%s]=%v", keyY, successRate[keyY])
268		}
269		if _, ok := latencyMS[keyY]; ok {
270			t.Fatalf("modelY latency should be untouched by modelX failures, got latencyMS[%s]=%v", keyY, latencyMS[keyY])
271		}
272	
273		if err := svc.RecordRouteAttempt(ctx, RouteAttempt{
274			Harness:  "fiz",
275			Provider: "providerA",
276			Model:    "modelY",
277			Status:   "success",
278			Duration: 50 * time.Millisecond,
279		}); err != nil {
280			t.Fatalf("RecordRouteAttempt success on modelY: %v", err)
281		}
282	
283		successRate, _ = svc.routeMetricSignals(time.Now(), 30*time.Second)
284		if got, want := successRate[keyX], 0.0; got != want {
285			t.Fatalf("after success on modelY: successRate[%s]=%v, want %v (cross-pollution)", keyX, got, want)
286		}
287		if got, want := successRate[keyY], 1.0; got != want {
288			t.Fatalf("after success on modelY: successRate[%s]=%v, want %v", keyY, got, want)
289		}
290	}
