344	func TestBuildRoutingInputs_GeminiQuotaGatesAutoRouting(t *testing.T) {
345		dir := t.TempDir()
346		quotaPath := filepath.Join(dir, "gemini-quota.json")
347		t.Setenv("FIZEAU_GEMINI_QUOTA_CACHE", quotaPath)
348		t.Setenv("FIZEAU_CODEX_QUOTA_CACHE", filepath.Join(dir, "missing-codex-quota.json"))
349		t.Setenv("FIZEAU_CLAUDE_QUOTA_CACHE", filepath.Join(dir, "missing-claude-quota.json"))
350	
351		registry := harnesses.NewRegistry()
352		svc := &service{opts: ServiceOptions{}, registry: registry}
353	
354		// Missing cache: no SubscriptionOK even with fresh auth.
355		t.Setenv("GOOGLE_API_KEY", "test")
356		gemini := routingHarnessEntry(t, svc.buildRoutingInputs(context.Background()).Harnesses, "gemini")
357		if gemini.SubscriptionOK || gemini.QuotaOK {
358			t.Fatalf("missing gemini quota cache must keep gemini out of auto-routing: %+v", gemini)
359		}
360	
361		// Stale snapshot: ineligible even though windows show headroom.
362		writeGeminiTestQuota(t, quotaPath, geminiTestQuotaSnapshot{
363			CapturedAt: time.Now().UTC().Add(-1 * time.Hour),
364			Source:     "pty",
365			Windows: []harnesses.QuotaWindow{
366				{Name: "Flash", LimitID: "gemini-flash", UsedPercent: 4, State: "ok"},
367			},
368		})
369		gemini = routingHarnessEntry(t, svc.buildRoutingInputs(context.Background()).Harnesses, "gemini")
370		if gemini.SubscriptionOK || !gemini.QuotaStale {
371			t.Fatalf("stale gemini quota: SubscriptionOK=%v QuotaStale=%v", gemini.SubscriptionOK, gemini.QuotaStale)
372		}
373	
374		// Fresh but all tiers exhausted: routing must still mark ineligible.
375		writeGeminiTestQuota(t, quotaPath, geminiTestQuotaSnapshot{
376			CapturedAt: time.Now().UTC(),
377			Source:     "pty",
378			Windows: []harnesses.QuotaWindow{
379				{Name: "Flash", LimitID: "gemini-flash", UsedPercent: 100, State: "exhausted"},
380				{Name: "Pro", LimitID: "gemini-pro", UsedPercent: 100, State: "exhausted"},
381			},
382		})
383		gemini = routingHarnessEntry(t, svc.buildRoutingInputs(context.Background()).Harnesses, "gemini")
384		if gemini.SubscriptionOK {
385			t.Fatalf("all tiers exhausted must block gemini auto-routing: %+v", gemini)
386		}
387		if gemini.QuotaTrend != routing.QuotaTrendExhausting {
388			t.Fatalf("all-exhausted snapshot should report exhausting trend, got %q", gemini.QuotaTrend)
389		}
390	
391		// Fresh with at least one non-exhausted tier: routing marks eligible.
392		writeGeminiTestQuota(t, quotaPath, geminiTestQuotaSnapshot{
393			CapturedAt: time.Now().UTC(),
394			Source:     "pty",
395			Windows: []harnesses.QuotaWindow{
396				{Name: "Flash", LimitID: "gemini-flash", UsedPercent: 4, State: "ok"},
397				{Name: "Pro", LimitID: "gemini-pro", UsedPercent: 100, State: "exhausted"},
398			},
399		})
400		gemini = routingHarnessEntry(t, svc.buildRoutingInputs(context.Background()).Harnesses, "gemini")
401		if !gemini.SubscriptionOK || !gemini.QuotaOK {
402			t.Fatalf("fresh gemini quota with headroom should mark gemini SubscriptionOK/QuotaOK: %+v", gemini)
403		}
404	}
