331	func writeServiceUsageSession(t *testing.T, logDir, sessionID string, startAt time.Time, start sessionlog.SessionStartData, end sessionlog.SessionEndData) {
332		t.Helper()
333		logger := sessionlog.NewLogger(logDir, sessionID)
