426	func harnessGoldenRecordHarnesses() []string {
427		raw := strings.TrimSpace(os.Getenv("FIZEAU_HARNESS_RECORD_HARNESSES"))
428		if raw == "" {
429			return []string{"claude", "codex"}
430		}
431		parts := strings.Split(raw, ",")
432		harnesses := make([]string, 0, len(parts))
433		for _, part := range parts {
434			if harness := strings.TrimSpace(part); harness != "" {
435				harnesses = append(harnesses, harness)
436			}
437		}
438		if len(harnesses) == 0 {
439			return []string{"claude", "codex"}
440		}
441		return harnesses
442	}
