458	func drainRawExecute(ctx context.Context, events <-chan ServiceEvent) ([]ServiceEvent, *DrainExecuteResult, error) {
459		result := &DrainExecuteResult{}
460		var raw []ServiceEvent
461		for {
462			select {
463			case <-ctx.Done():
464				return raw, result, ctx.Err()
465			case ev, ok := <-events:
466				if !ok {
467					if result.Final == nil {
468						return raw, result, context.Canceled
469					}
470					return raw, result, nil
471				}
472				raw = append(raw, ev)
473				decoded, err := DecodeServiceEvent(ev)
474				if err != nil {
475					return raw, result, err
476				}
477				result.append(decoded)
478			}
479		}
480	}
