82	// setFakeCodexHarness installs h as the "codex" entry in harnessInstanceHook
83	// so both New() and newTestService() pick it up. Restores the previous hook
84	// via t.Cleanup.
85	func setFakeCodexHarness(t *testing.T, h *fakeCodexQuotaHarness) {
86		t.Helper()
87		prev := harnessInstanceHook
88		harnessInstanceHook = func(instances map[string]harnesses.Harness) map[string]harnesses.Harness {
89			instances["codex"] = h
90			return instances
91		}
92		t.Cleanup(func() { harnessInstanceHook = prev })
93	}
