165			t.Fatalf("EndpointStatus length: got %d, want 1", len(info.EndpointStatus))
166		}
167		if info.EndpointStatus[0].Status != "connected" || info.EndpointStatus[0].ModelCount != 2 || info.EndpointStatus[0].LastSuccessAt.IsZero() {
168			t.Fatalf("EndpointStatus[0]: %#v", info.EndpointStatus[0])
