516	// TestHealthCheck_ClaudeRefreshesQuotaWhenStale verifies that HealthCheck
517	// triggers a quota cache refresh when the cached snapshot is older than
518	// default quota refresh debounce (15m).
519	func TestHealthCheck_ClaudeRefreshesQuotaWhenStale(t *testing.T) {
520		dir := t.TempDir()
521		cachePath := filepath.Join(dir, "claude-quota.json")
522		t.Setenv("FIZEAU_CLAUDE_QUOTA_CACHE", cachePath)
523	
524		// Write a snapshot older than the 15m debounce.
525		staleSnap := claudeharness.ClaudeQuotaSnapshot{
526			CapturedAt:        time.Now().UTC().Add(-20 * time.Minute),
527			FiveHourRemaining: 80,
528			FiveHourLimit:     100,
529			WeeklyRemaining:   90,
530			WeeklyLimit:       100,
531			Source:            "pty",
532		}
533		if err := claudeharness.WriteClaudeQuota(cachePath, staleSnap); err != nil {
534			t.Fatalf("setup: WriteClaudeQuota: %v", err)
535		}
536	
537		// Inject a fake refresher so no real PTY probe is invoked.
538		refreshCalled := false
539		setClaudeQuotaRefresherForTest(t, func(timeout time.Duration) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error) {
540			refreshCalled = true
541			return []harnesses.QuotaWindow{
542				{LimitID: "session", UsedPercent: 20},
543				{LimitID: "weekly-all", UsedPercent: 10},
544			}, nil, nil
545		})
546	
547		svc := newTestService(t, ServiceOptions{})
548		// HealthCheck for "claude" requires the binary to be discoverable.
549		// If claude is not in PATH, the harness is unavailable → the quota refresh
550		// is never reached. To keep the test self-contained we call the helper
551		// directly rather than going through HealthCheck's availability gate.
552		svc.healthCheckRefreshClaudeQuota(context.Background())
553	
554		if !refreshCalled {
555			t.Error("expected healthCheckClaudeQuotaRefresher to be called for stale cache")
556		}
557	
558		// Verify the cache was rewritten with a newer timestamp.
559		loaded, ok := claudeharness.ReadClaudeQuotaFrom(cachePath)
560		if !ok {
561			t.Fatal("expected cache file to exist after refresh")
562		}
563		if !loaded.CapturedAt.After(staleSnap.CapturedAt) {
564			t.Errorf("expected cache CapturedAt to be newer than stale snapshot: got %v, stale was %v",
565				loaded.CapturedAt, staleSnap.CapturedAt)
566		}
567	}
