887	func resetPrimaryQuotaRefreshForTest(t *testing.T) {
888		t.Helper()
889		primaryQuotaRefresh.mu.Lock()
890		oldLast := primaryQuotaRefresh.lastAttempt
891		oldInFlight := primaryQuotaRefresh.inFlight
