930	func waitForQuotaRefreshFiles(t *testing.T, paths ...string) {
931		t.Helper()
932		deadline := time.After(time.Second)
933		for {
934			allPresent := true
935			for _, path := range paths {
936				if _, err := os.Stat(path); err != nil {
937					allPresent = false
938					break
939				}
940			}
941			if allPresent {
942				return
943			}
944			select {
945			case <-deadline:
946				t.Fatalf("timed out waiting for quota refresh files: %v", paths)
947			default:
948				time.Sleep(time.Millisecond)
949			}
950		}
951	}
