28	// codexQuotaCachePath returns the durable location for the Codex quota cache.
29	func codexQuotaCachePath() (string, error) {
30		if path := os.Getenv(codexQuotaCacheEnv); path != "" {
31			return path, nil
32		}
33		if xdg := os.Getenv("XDG_STATE_HOME"); xdg != "" {
34			return filepath.Join(xdg, productinfo.ConfigDir, "codex-quota.json"), nil
35		}
36		home, err := os.UserHomeDir()
37		if err != nil {
38			return "", err
39		}
40		return filepath.Join(home, ".local", "state", productinfo.ConfigDir, "codex-quota.json"), nil
41	}
