75			{"connection refused", `dial tcp 192.168.2.106:8020: connection refused`},
76			{"502 bad gateway", `POST "http://bragi:1234/v1/chat/completions": 502 Bad Gateway `},
77			{"no route to host", `dial tcp: no route to host`},
78		}
79		for _, c := range cases {
80			t.Run(c.name, func(t *testing.T) {
81				svc := routeAttemptTestService(t, 30*time.Second)
82	
83				before, err := svc.ResolveRoute(context.Background(), RouteRequest{Model: "qwen"})
84				if err != nil {
85					t.Fatalf("ResolveRoute before failure: %v", err)
86				}
87				if before.Provider != "bragi" {
88					t.Fatalf("baseline provider: got %q, want bragi", before.Provider)
89				}
90	
91				if err := svc.RecordRouteAttempt(context.Background(), RouteAttempt{
92					Harness:  "fiz",
93					Provider: "bragi",
94					Model:    "qwen",
95					Status:   "failed",
96					Error:    c.err,
97				}); err != nil {
98					t.Fatalf("RecordRouteAttempt: %v", err)
99				}
100	
101				// After a dial-class failure, bragi must be hard-gated — its
102				// candidate row should be Eligible=false with FilterReasonUnhealthy.
103				after, err := svc.ResolveRoute(context.Background(), RouteRequest{Model: "qwen"})
104				if err != nil {
105					t.Fatalf("ResolveRoute after failure: %v", err)
106				}
107				if after.Provider == "bragi" {
108					t.Fatalf("after dial failure provider: got bragi, want hard-gated to alternative")
109				}
110				var bragiCand *RouteCandidate
111				for i := range after.Candidates {
112					if after.Candidates[i].Provider == "bragi" {
113						bragiCand = &after.Candidates[i]
114						break
115					}
116				}
117				if bragiCand == nil {
118					t.Fatal("bragi candidate row missing from decision")
119				}
120				if bragiCand.Eligible {
121					t.Errorf("bragi should be Eligible=false after dial failure; got Eligible=true")
122				}
123				if !strings.Contains(bragiCand.Reason, "known unreachable") {
124					t.Errorf("bragi.Reason = %q, want it to contain 'known unreachable'", bragiCand.Reason)
125				}
126	
127				// Explicit provider pin still selects bragi (operator bypass).
128				pinned, err := svc.ResolveRoute(context.Background(), RouteRequest{Model: "qwen", Provider: "bragi"})
129				if err != nil {
130					t.Fatalf("ResolveRoute with provider pin: %v", err)
131				}
132				if pinned.Provider != "bragi" {
133					t.Fatalf("explicit pin after dial failure: got %q, want bragi", pinned.Provider)
134				}
135			})
136		}
137	}
